const d = $input.first().json;
const TC = Number(d.tc);

// Ingreso USD desde BD (con monto_proximo si corresponde)
const ingresoUSD = Number(d.ingreso_usd);
const ingresoARS = ingresoUSD * TC;

const cuotasGalicia = Number(d.cuotas_galicia_actual);
const cuotasNaranja = Number(d.cuotas_naranja_actual);
const gastosFijos = Number(d.gastos_fijos_propios) + Number(d.gastos_fijos_compartidos);
// Valores operativos fijos (actualizar en BD configuracion cuando cambien)
const jorge = 20000;
const juanBuffer = 15000;
const colchon = 250000;
const reservaGalicia = Number(d.cuotas_galicia_proximo);

const totalARS = Math.round(
  cuotasGalicia + cuotasNaranja + gastosFijos +
  jorge + juanBuffer + colchon + reservaGalicia
);

const usdTarjetas = 490;
const sobraARS = Math.round(ingresoARS - totalARS);
const sobraUSD = ingresoUSD - usdTarjetas;

const fmt = n => Math.round(Number(n)).toLocaleString('es-AR');
const mesesES = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const hoy = new Date();
const mesActual = mesesES[hoy.getMonth()];
const mesSiguiente = mesesES[(hoy.getMonth() + 1) % 12];

const cvu = '0000003100037318678144';
const alias = 'luismolinareinoso.mp';

let msg = `💰 *LIQUIDACIÓN ${mesActual.toUpperCase()}*\n`;
msg += `━━━━━━━━━━━━━━━━\n\n`;
msg += `💵 U$D ${fmt(ingresoUSD)} × $${fmt(TC)} = *$${fmt(ingresoARS)}*\n\n`;
msg += `📋 *PEDIRLE A JUAN*\n`;
msg += `→ ARS: *$${fmt(totalARS)}*\n`;
msg += `→ USD (tarjetas): *U$D ${usdTarjetas}*\n\n`;
msg += `📊 *DETALLE*\n`;
msg += `🏦 Galicia: $${fmt(cuotasGalicia)}\n`;
msg += `🟠 Naranja: $${fmt(cuotasNaranja)}\n`;
msg += `📌 Gastos fijos: $${fmt(gastosFijos)}\n`;
msg += `👨‍💼 Jorge + Juan est.: $${fmt(jorge + juanBuffer)}\n`;
msg += `🛒 Colchón operativo: $${fmt(colchon)}\n`;
msg += `📦 Reserva Galicia ${mesSiguiente}: $${fmt(reservaGalicia)}\n\n`;
msg += `💎 *JUAN INVIERTE*\n`;
msg += sobraARS > 0 ? `→ ARS: $${fmt(sobraARS)}\n` : `→ ARS: ⚠️ Sin excedente\n`;
msg += `→ USD extra: U$D ${sobraUSD}\n\n`;
msg += `🏦 *TRANSFERÍ HOY A MP*\n`;
msg += `Reserva Galicia ${mesSiguiente}: *$${fmt(reservaGalicia)}*\n`;
msg += `CVU: \`${cvu}\`\n`;
msg += `Alias: \`${alias}\`\n\n`;
msg += `━━━━━━━━━━━━━━━━\n`;
msg += `💡 _Copiá el bloque de Juan y mandáselo._`;

return { mensaje: msg, reserva_galicia: reservaGalicia, mes_siguiente: mesSiguiente, tc: TC, ingreso_usd: ingresoUSD };

const reserva = Number($input.first().json.reserva_galicia);
const fmt = n => Math.round(Number(n)).toLocaleString('es-AR');
const cvu = '0000003100037318678144';
const alias = 'luismolinareinoso.mp';

let msg = `🔔 *RECORDATORIO — GALICIA MAÑANA*\n\n`;
msg += `Mañana vence tu Mastercard Galicia.\n`;
msg += `Tenés reservados *$${fmt(reserva)}* en Mercado Pago.\n\n`;
msg += `✅ Transferí hoy a Galicia antes del cierre bancario.\n\n`;
msg += `MP Alias: \`${alias}\``;

return { mensaje: msg };
